1	export interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_SURCHARGE = 1.1;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_BUNDLE_BASE = 60;
20	const COMPONENT_BUNDLE_SIZE = 3;
21	const BUNDLEABLE_COMPONENTS = new Set(["rune", "moonstone"]);
22	
23	function roundUpToWholeG(amount: number): number {
24	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
25	  return Math.ceil(Math.round(amount * 100) / 100);
26	}
27	
28	const CURSED_SURCHARGE = 1.5;
29	const HIGH_ENCHANTMENT_SURCHARGE = 1.3;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	
32	const LOYALTY_DISCOUNT = 0.8;
33	const LOYALTY_YEARS_THRESHOLD = 2;
34	
35	function loyaltyDiscountFor(customer: { yearsWithMHPCO: number }): number {
36	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 1;
37	}
38	
39	function isHighlyEnchanted(item: Item): boolean {
40	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
41	}
42	
43	function riskMultiplier(item: Item): number {
44	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE : 1;
45	  const enchantmentMultiplier = isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 1;
46	  return cursedMultiplier * enchantmentMultiplier;
47	}
48	
49	function premiumFor(item: Item, loyaltyDiscount: number): number {
50	  const basePremium = BASE_PREMIUMS[item.type];
51	  return roundUpToWholeG(basePremium * riskMultiplier(item) * loyaltyDiscount * FIRST_INSURANCE_SURCHARGE);
52	}
53	
54	function isThreeAlikeBundle(items: Item[]): boolean {
55	  if (items.length !== COMPONENT_BUNDLE_SIZE) return false;
56	  const firstType = items[0].type;
57	  return (
58	    BUNDLEABLE_COMPONENTS.has(firstType) &&
59	    items.every((item) => item.type === firstType)
60	  );
61	}
62	
63	function bundlePremium(): number {
64	  return roundUpToWholeG(COMPONENT_BUNDLE_BASE * FIRST_INSURANCE_SURCHARGE);
65	}
66	
67	export function quote(
68	  customer: { yearsWithMHPCO: number },
69	  items: Item[],
70	  _previousContracts?: number,
71	): number {
72	  const loyaltyDiscount = loyaltyDiscountFor(customer);
73	  const itemsTotal = isThreeAlikeBundle(items)
74	    ? bundlePremium()
75	    : items.reduce((sum, item) => sum + premiumFor(item, loyaltyDiscount), 0);
76	  return itemsTotal + PROCESSING_FEE;
77	}
78	
79	export function claim(): number {
80	  return undefined as unknown as number;
81	}
